code.C:
#include <stdio.h>

int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

int min_square_plots(int N, int M) {
    int g = gcd(N, M);
    return (N * M) / (g * g);
}

int main() {
    int T, N, M;
    scanf("%d", &T);

    while (T--) {
        scanf("%d %d", &N, &M);
        printf("%d\n", min_square_plots(N, M));
    }

    return 0;
}

