function gcd(a, b) {
    // Implement the Euclidean algorithm to find GCD
    while (b !== 0) {
        let temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

function Rectsq(input) {
    // Split the input into an array of test cases
    const testCases = input.trim().split('\n').slice(1); // Remove the first line (number of test cases)

    // Process each test case
    for (const testCase of testCases) {
        // Parse the length and breadth of the land
        const [N, M] = testCase.split(' ').map(Number);

        // Calculate the GCD of the length and breadth
        const G = gcd(N, M);

        // Calculate the minimum number of square plots with equal area
        const minPlots = (N * M) / (G * G);

        // Output the result for the current test case
        console.log(minPlots);
    }
}

